import apiClient from './api';

// 认证相关的API服务
const authService = {
  // 用户登录
  async login(username, password) {
    return apiClient.post('/api/auth/signin', {
      username,
      password
    });
  },

  // 用户注册
  async register(username, email, password, nickname) {
    return apiClient.post('/api/auth/signup', {
      username,
      email,
      password,
      nickname
    });
  },

  // 获取当前用户信息
  async getCurrentUser() {
    return apiClient.get('/api/auth/user');
  },

  // 退出登录
  async logout() {
    // 实际上退出登录只需要清除本地存储的token
    // 这里可以添加一些服务端的登出逻辑，例如令牌失效等
    localStorage.removeItem('user');
    return Promise.resolve();
  }
};

export default authService;
